import React from "react";
import { Link, useNavigate } from "react-router-dom";

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem("token");

  const handleLogout = () => {
    localStorage.removeItem("token");
    alert("You have logged out successfully!");
    navigate("/");
  };

  return (
    <nav className="flex items-center justify-between bg-green-700 text-white px-6 py-3 shadow-md">
      <h1
        className="text-2xl font-bold cursor-pointer"
        onClick={() => navigate("/")}
      >
        🌱 LeafLens
      </h1>

      <div className="flex space-x-4">
        <Link
          to="/"
          className="hover:bg-green-600 px-3 py-2 rounded transition"
        >
          Home
        </Link>

        {!token && (
          <>
            <Link
              to="/login"
              className="hover:bg-green-600 px-3 py-2 rounded transition"
            >
              Login
            </Link>
            <Link
              to="/register"
              className="hover:bg-green-600 px-3 py-2 rounded transition"
            >
              Register
            </Link>
          </>
        )}

        {token && (
          <>
            <Link
              to="/detect"
              className="hover:bg-green-600 px-3 py-2 rounded transition"
            >
              Detect
            </Link>
            <button
              onClick={handleLogout}
              className="bg-red-500 hover:bg-red-600 px-3 py-2 rounded transition"
            >
              Logout
            </button>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
